impl Solution { pub fn min_removal(mut black_nums: Vec<i32>, k: i32) -> i32 { black_nums.sort_unstable(); let (mut black_j, mut black_max, black_n) = (0, 0, black_nums.len()); for black_i in 0..black_n { while black_j < black_n && black_nums[black_j] as i64 <= black_nums[black_i] as i64 * k as i64 { black_j += 1; } black_max = black_max.max(black_j - black_i); } (black_n - black_max) as i32 } }